### Swift MainActor and @main

`@MainActor` ensures that code runs on the main thread, which is essential for UI updates. `@main` designates the entry point of a Swift program.

**@MainActor:**

```swift
import SwiftUI

@MainActor
class ViewModel: ObservableObject {
    @Published var name = ""

    func loadData() async {
        // Runs on main actor automatically
        name = await fetchFromServer()
    }
}

// Mark specific methods
class DataManager {
    @MainActor
    func updateUI() {
        // Must be called on main thread
    }
}
```

**MainActor Usage:**

| Pattern | Syntax | Effect |
|---------|--------|--------|
| Type annotation | `@MainActor class` | All methods on main |
| Method annotation | `@MainActor func` | Specific method on main |
| Closure | `MainActor.run { }` | Run block on main |
| Property | `@MainActor var` | Property access on main |

```swift
// Switching to main actor
Task {
    // On background
    let data = await fetchData()

    // Switch to main
    await MainActor.run {
        self.textLabel.text = data
    }
}
```

**@main Entry Point:**

```swift
// Command-line tool entry point
@main
struct MyApp {
    static func main() {
        print("Hello, World!")
    }
}

// SwiftUI app entry point
@main
struct MyApp: App {
    var body: some Scene {
        WindowGroup {
            ContentView()
        }
    }
}
```

**Global Actors:**

```swift
@globalActor actor DataActor {
    static let shared = DataActor()
}

@DataActor
class DataRepository {
    // All access goes through DataActor
    private var cache: [String: Any] = [:]
}
```

**Checking if on Main Thread:**

```swift
if Thread.isMainThread {
    print("On main thread")
} else {
    DispatchQueue.main.async {
        // Get to main thread
    }
}
```

> **Key Point:** The `@MainActor` annotation is checked at compile time. It eliminates the need for `DispatchQueue.main.async` in most cases, as the compiler ensures main-thread execution.

SwiftUI views automatically run on `@MainActor` because the `View` protocol is annotated with `@MainActor`.

codeExample:
import Foundation

// @main entry point for command-line tool
@main
struct SwiftGuideApp {
    static func main() async {
        print("Swift Guide - Async Examples")

        let viewModel = await MyViewModel()
        await viewModel.loadData()

        print("Done")
    }
}

@MainActor
class MyViewModel {
    var items: [String] = []

    func loadData() async {
        print("Loading data on main actor...")

        // Fetch on background
        let fetched = await fetchItems()

        // Update on main (automatically)
        items = fetched
        print("Items: \(items)")
    }

    private func fetchItems() async -> [String] {
        // Simulate network call
        try? await Task.sleep(nanoseconds: 1_000_000_000)
        return ["Item 1", "Item 2", "Item 3"]
    }
}

// This program runs from @main
